package main

func solutionBlendByte(s, d, a uint8) uint8 {
	return uint8((uint32(s)*uint32(a) + uint32(d)*uint32(255-a) + 127) / 255)
}

func solutionChecksumBytes(data []byte) uint64 {
	var hash uint64 = 1469598103934665603
	for _, b := range data {
		hash ^= uint64(b)
		hash *= 1099511628211
	}
	return hash
}

func run(src, dst []byte, width, height, iters int) uint64 {
	// Preallocate full output slice once to avoid append overhead across iterations
	out := make([]byte, len(src))
	pixels := width * height
	var hash uint64

	for iter := 0; iter < iters; iter++ {
		for i := 0; i < pixels; i++ {
			base := i * 4
			// Load and precompute shared values once per pixel to avoid redundant work
			srcA := src[base+3]
			a32 := uint32(srcA)
			aInv32 := uint32(255 - srcA)

			// Blend R channel
			sR := uint32(src[base])
			dR := uint32(dst[base])
			out[base] = uint8((sR*a32 + dR*aInv32 + 127) / 255)

			// Blend G channel
			sG := uint32(src[base+1])
			dG := uint32(dst[base+1])
			out[base+1] = uint8((sG*a32 + dG*aInv32 + 127) / 255)

			// Blend B channel
			sB := uint32(src[base+2])
			dB := uint32(dst[base+2])
			out[base+2] = uint8((sB*a32 + dB*aInv32 + 127) / 255)

			// Set fixed output alpha
			out[base+3] = 255
		}
		hash = solutionChecksumBytes(out)
	}
	return hash
}
